import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Volume2, VolumeX, Settings } from 'lucide-react';
import { Toaster } from 'sonner';

// Import refactored components
import { Sidebar, TickerTape, PriceAlertNotification, AlertSettingsPanel } from './components';
import { useWebSocket, usePriceAlerts } from './hooks';
import { TickerModalProvider } from './hooks/useTickerModal';
import { 
  DataCacheProvider, 
  TrainingModeProvider, 
  AppStateProvider, 
  ConnectionManagerProvider,
  SystemStatusProvider,
  FocusModeProvider,
  StartupManagerProvider,
  useSystemStatus,
  TrainCommandProvider
} from './contexts';
import { WebSocketDataProvider } from './contexts/WebSocketDataContext';
import api from './utils/api';
import { resetStaggerCounter } from './utils/safePolling';
import StartupModal from './components/StartupModal';
import StartupStatusDashboard from './components/StartupStatusDashboard';
import TrainingModeIndicator from './components/TrainingModeIndicator';
import ErrorBoundary from './components/ErrorBoundary';
import SystemStatusBar from './components/SystemStatusBar';
import FocusModeSelector from './components/FocusModeSelector';

// Import pages
import {
  ChartsPage,
  TradeJournalPage,
} from './pages';
import CommandCenterPage from './pages/CommandCenterPage';
import GlossaryPage from './pages/GlossaryPage';
import SettingsPage from './pages/SettingsPage';
import NIA from './components/NIA';

import './App.css';

// Alias the imported ErrorBoundary to avoid naming conflicts
// The imported one is more robust with retry functionality
const WidgetErrorBoundary = ErrorBoundary;

// Suppress third-party script errors in development
if (typeof window !== 'undefined') {
  // Hide the webpack dev server error overlay
  const hideErrorOverlay = () => {
    const overlay = document.getElementById('webpack-dev-server-client-overlay');
    if (overlay) {
      overlay.style.display = 'none';
    }
    // Also hide any iframe overlays
    document.querySelectorAll('iframe').forEach(iframe => {
      if (iframe.id?.includes('overlay') || iframe.src?.includes('overlay')) {
        iframe.style.display = 'none';
      }
    });
  };
  
  // Run periodically to catch any newly created overlays
  setInterval(hideErrorOverlay, 500);
  
  window.addEventListener('error', (event) => {
    if (event.message === 'Script error.' || 
        event.filename?.includes('tradingview') ||
        event.filename?.includes('widget') ||
        event.message?.includes('Script error')) {
      event.preventDefault();
      event.stopPropagation();
      hideErrorOverlay();
      return false;
    }
  });
  
  // Also catch unhandled promise rejections
  window.addEventListener('unhandledrejection', (event) => {
    if (event.reason?.message?.includes('Script error') ||
        event.reason?.stack?.includes('tradingview')) {
      event.preventDefault();
      hideErrorOverlay();
    }
  });
}

// ===================== WebSocket Status Sync =====================
// This component syncs the WebSocket connection state to the SystemStatusContext
const WebSocketStatusSync = ({ isConnected }) => {
  const { setWebSocketConnected } = useSystemStatus();
  
  useEffect(() => {
    setWebSocketConnected(isConnected);
  }, [isConnected, setWebSocketConnected]);
  
  return null;
};

// ===================== MAIN APP =====================
function App() {
  // Startup status dashboard - shows system initialization progress
  const [showStartupStatus, setShowStartupStatus] = useState(false);
  const [startupStatusMinimized, setStartupStatusMinimized] = useState(false);
  
  // Startup modal state - shows wave-based loading progress
  const [showStartupModal, setShowStartupModal] = useState(() => {
    // Check if user opted out
    const skipStartup = localStorage.getItem('tradecommand_skip_startup');
    return skipStartup !== 'true';
  });
  
  // Controls whether main content renders (delays until startup modal is done)
  const [appReady, setAppReady] = useState(() => {
    const skipStartup = localStorage.getItem('tradecommand_skip_startup');
    return skipStartup === 'true'; // Only ready immediately if skipping startup
  });
  
  // Persist activeTab in localStorage so it survives page refresh
  const [activeTab, setActiveTab] = useState(() => {
    // Check URL hash for direct navigation (e.g., #mockups)
    const hash = window.location.hash.replace('#', '');
    if (hash === 'mockups') return 'mockups';
    
    const saved = localStorage.getItem('tradecommand_activeTab');
    return saved || 'command-center';
  });
  const [dashboardData, setDashboardData] = useState({ stats: {}, overview: {}, alerts: [], watchlist: [] });
  const [loading, setLoading] = useState(true);
  const [streamingQuotes, setStreamingQuotes] = useState({});
  const [showAlertSettings, setShowAlertSettings] = useState(false);
  
  // Global IB Connection State - shared across all pages
  const [ibConnected, setIbConnected] = useState(false);
  const [ibConnectionChecked, setIbConnectionChecked] = useState(false);

  // ============= WebSocket-pushed state (replaces polling) =============
  const [wsBotStatus, setWsBotStatus] = useState(null);
  const [wsBotTrades, setWsBotTrades] = useState([]);
  const [wsScannerAlerts, setWsScannerAlerts] = useState([]);
  const [wsScannerStatus, setWsScannerStatus] = useState(null);
  const [wsSmartWatchlist, setWsSmartWatchlist] = useState([]);
  const [wsCoachingNotifications, setWsCoachingNotifications] = useState([]);
  const [wsConfidenceGate, setWsConfidenceGate] = useState(null);
  const [wsTrainingStatus, setWsTrainingStatus] = useState(null);
  const [wsMarketRegime, setWsMarketRegime] = useState(null);
  const [lastWsMessage, setLastWsMessage] = useState(null);

  // Save activeTab to localStorage when it changes
  useEffect(() => {
    localStorage.setItem('tradecommand_activeTab', activeTab);
  }, [activeTab]);
  
  // Check IB connection status on app load and periodically
  // Global IB busy state
  const [ibBusy, setIbBusy] = useState(false);
  const [ibBusyOperation, setIbBusyOperation] = useState(null);
  const [ibPusherStatus, setIbPusherStatus] = useState(null);

  const checkIbConnection = useCallback(async () => {
    try {
      const res = await api.get('/api/ib/status');
      const connected = res.data?.connected || false;
      const busy = res.data?.is_busy || false;
      const busyOp = res.data?.busy_operation || null;
      const pusher = res.data?.pusher || null;
      
      setIbConnected(connected);
      setIbConnectionChecked(true);
      setIbBusy(busy);
      setIbBusyOperation(busyOp);
      setIbPusherStatus(pusher);
      
      return connected;
    } catch (err) {
      console.error('IB status check failed:', err);
      setIbConnected(false);
      setIbConnectionChecked(true);
      setIbBusy(false);
      setIbPusherStatus(null);
      return false;
    }
  }, []);
  
  // Connect to IB - called from any page
  const connectToIb = useCallback(async () => {
    try {
      await api.post('/api/ib/connect');
      const connected = await checkIbConnection();
      return connected;
    } catch (err) {
      console.error('IB connect failed:', err);
      return false;
    }
  }, [checkIbConnection]);
  
  // Check connection on app load - only after startup modal completes
  useEffect(() => {
    if (appReady) checkIbConnection();
  }, [checkIbConnection, appReady]);
  
  // Periodic connection check as FALLBACK only (60 seconds)
  // Primary IB status comes via WebSocket now
  useEffect(() => {
    if (!appReady) return;
    const interval = setInterval(async () => {
      // Only poll if not getting WebSocket updates
      await checkIbConnection();
    }, 60000);  // Reduced to 60s - WebSocket handles real-time updates
    return () => clearInterval(interval);
  }, [checkIbConnection, ibConnectionChecked, appReady]);

  // WebSocket handler for real-time updates (quotes + system status)
  const handleWebSocketMessage = useCallback((message) => {
    // Forward ALL messages to the WebSocket context provider
    setLastWsMessage(message);
    
    // Quote updates
    if (message.type === 'quotes' || message.type === 'initial') {
      const quotesMap = {};
      message.data.forEach(quote => {
        quotesMap[quote.symbol] = quote;
      });
      setStreamingQuotes(prev => ({ ...prev, ...quotesMap }));
      
      // Update indices in dashboard data
      setDashboardData(prev => {
        const updatedIndices = prev.overview?.indices?.map(idx => {
          const updated = quotesMap[idx.symbol];
          return updated ? { ...idx, ...updated } : idx;
        }) || [];
        
        const updatedMovers = prev.overview?.top_movers?.map(mover => {
          const updated = quotesMap[mover.symbol];
          return updated ? { ...mover, ...updated } : mover;
        }) || [];
        
        return {
          ...prev,
          overview: {
            ...prev.overview,
            indices: updatedIndices,
            top_movers: updatedMovers
          }
        };
      });
    }
    
    // IB Connection status (replaces polling)
    else if (message.type === 'ib_status') {
      const { connected, busy } = message.data;
      setIbConnected(connected);
      setIbConnectionChecked(true);
      setIbBusy(busy);
    }
    
    // Trading bot status (replaces polling)
    else if (message.type === 'bot_status') {
      setWsBotStatus(message.data);
    }
    
    // Trading bot trades (replaces polling)
    else if (message.type === 'bot_trades') {
      setWsBotTrades(message.data);
    }
    
    // Scanner status (replaces polling)
    else if (message.type === 'scanner_status') {
      setWsScannerStatus(message.data);
    }
    
    // Scanner alerts (replaces polling)
    else if (message.type === 'scanner_alerts') {
      setWsScannerAlerts(message.data);
    }
    
    // Smart watchlist (replaces polling)
    else if (message.type === 'smart_watchlist') {
      setWsSmartWatchlist(message.data);
    }
    
    // AI Coaching notifications (replaces polling)
    else if (message.type === 'coaching_notifications') {
      setWsCoachingNotifications(prev => {
        // Merge new notifications, avoiding duplicates
        const existingIds = new Set(prev.map(n => n.id));
        const newNotifications = message.data.filter(n => !existingIds.has(n.id));
        return [...newNotifications, ...prev].slice(0, 50); // Keep last 50
      });
    }
    
    // Confidence Gate updates (replaces SentComIntelligencePanel polling)
    else if (message.type === 'confidence_gate') {
      setWsConfidenceGate(message.data);
    }
    
    // Training pipeline status (replaces TrainingPipelinePanel polling)
    else if (message.type === 'training_status') {
      setWsTrainingStatus(message.data);
    }
    
    // Market regime (replaces MarketRegimeWidget polling)
    else if (message.type === 'market_regime') {
      setWsMarketRegime(message.data);
    }
  }, []);

  const { isConnected, lastUpdate, sendTrainCommand } = useWebSocket(handleWebSocketMessage);
  
  // Price Alerts Integration
  const {
    alerts: priceAlerts,
    audioEnabled,
    setAudioEnabled,
    alertThreshold,
    setAlertThreshold,
    initializeAudio,
    dismissAlert
  } = usePriceAlerts(streamingQuotes, dashboardData.watchlist);

  const loadDashboardData = useCallback(async () => {
    setLoading(true);
    try {
      const [statsRes, overviewRes, alertsRes, watchlistRes] = await Promise.all([
        api.get('/api/dashboard/stats'),
        api.get('/api/market/overview'),
        api.get('/api/alerts', { params: { unread_only: true } }),
        api.get('/api/watchlist')
      ]);
      setDashboardData({
        stats: statsRes.data,
        overview: overviewRes.data,
        alerts: alertsRes.data.alerts,
        watchlist: watchlistRes.data.watchlist
      });
    } catch (err) { console.error('Failed to load dashboard:', err); }
    finally { setLoading(false); }
  }, []);

  useEffect(() => { if (appReady) loadDashboardData(); }, [loadDashboardData, appReady]);
  
  // Fetch initial scanner alerts via REST (don't wait for WebSocket stream)
  useEffect(() => {
    if (!appReady) return;
    const fetchInitialAlerts = async () => {
      try {
        const res = await api.get('/api/live-scanner/alerts');
        if (res.data?.alerts?.length > 0) {
          setWsScannerAlerts(res.data.alerts);
        }
      } catch (err) {
        // Non-critical, WebSocket will push alerts later
      }
    };
    fetchInitialAlerts();
  }, [appReady]);
  
  // Initialize audio on first user interaction
  useEffect(() => {
    const handleFirstInteraction = () => {
      initializeAudio();
      document.removeEventListener('click', handleFirstInteraction);
    };
    document.addEventListener('click', handleFirstInteraction);
    return () => document.removeEventListener('click', handleFirstInteraction);
  }, [initializeAudio]);

  // IB connection props to pass to pages that need it
  const ibProps = {
    ibConnected,
    ibConnectionChecked,
    connectToIb,
    checkIbConnection,
    ibBusy,
    ibBusyOperation,
    ibPusherStatus,
    // WebSocket status for quotes streaming
    wsConnected: isConnected,
    wsLastUpdate: lastUpdate,
    // WebSocket-pushed data (replaces polling in child components)
    wsBotStatus,
    wsBotTrades,
    wsScannerAlerts,
    wsScannerStatus,
    wsSmartWatchlist,
    wsCoachingNotifications,
    // WebSocket-pushed AI data
    wsConfidenceGate,
    wsTrainingStatus,
    wsMarketRegime,
  };

  const renderPage = () => {
    // Command Center and NIA are rendered separately (always mounted)
    switch (activeTab) {
      case 'command-center': return null;
      case 'nia': return null;
      case 'chart': return <ErrorBoundary name="Charts"><ChartsPage {...ibProps} /></ErrorBoundary>;
      case 'trade-journal': return <ErrorBoundary name="Trade Journal"><TradeJournalPage /></ErrorBoundary>;
      case 'glossary': return <ErrorBoundary name="Glossary"><GlossaryPage /></ErrorBoundary>;
      case 'settings': return <ErrorBoundary name="Settings"><SettingsPage /></ErrorBoundary>;
      default: return null;
    }
  };

  return (
    <AppStateProvider>
    <StartupManagerProvider>
    <SystemStatusProvider>
    <ConnectionManagerProvider>
    <FocusModeProvider>
    <TrainingModeProvider>
    <TrainCommandProvider value={sendTrainCommand}>
    <DataCacheProvider>
    <WebSocketDataProvider wsMessage={lastWsMessage}>
    <TickerModalProvider>
      {/* Sync WebSocket status to SystemStatusContext */}
      <WebSocketStatusSync isConnected={isConnected} />
      <div className="min-h-screen" style={{ background: 'var(--bg-default)' }} onClick={initializeAudio}>
        {/* Startup Modal - Real service verification */}
        {showStartupModal && (
          <StartupModal onComplete={() => {
            setShowStartupModal(false);
            resetStaggerCounter(); // Reset stagger so components spread out from 0
            setAppReady(true); // App is ready because modal verified everything
          }} />
        )}
        
        {/* Startup Status Dashboard - shows system initialization progress */}
        {showStartupStatus && !showStartupModal && appReady && (
          <StartupStatusDashboard 
            onClose={() => setShowStartupStatus(false)}
            minimized={startupStatusMinimized}
            onMinimize={() => setStartupStatusMinimized(!startupStatusMinimized)}
          />
        )}
      
      {/* Toast notifications */}
      <Toaster 
        position="top-right" 
        richColors 
        theme="dark"
        toastOptions={{
          style: { background: '#18181b', border: '1px solid rgba(255,255,255,0.1)' }
        }}
      />
      
      {/* Show loading state while app initializes */}
      {!appReady && !showStartupModal && (
        <div className="fixed inset-0 flex items-center justify-center bg-zinc-900 z-40">
          <div className="text-center">
            <div className="w-12 h-12 border-4 border-cyan-500/30 border-t-cyan-500 rounded-full animate-spin mx-auto mb-4"></div>
            <p className="text-zinc-400 text-sm">Initializing systems...</p>
          </div>
        </div>
      )}
      
      {/* Main app content - only renders when ready */}
      {appReady && (
        <>
          <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      
      {/* Price Alert Notifications */}
      <PriceAlertNotification 
        alerts={priceAlerts} 
        onDismiss={dismissAlert}
        audioEnabled={audioEnabled}
        setAudioEnabled={setAudioEnabled}
      />
      
      {/* Alert Settings Panel */}
      <AnimatePresence>
        {showAlertSettings && (
          <AlertSettingsPanel
            audioEnabled={audioEnabled}
            setAudioEnabled={setAudioEnabled}
            alertThreshold={alertThreshold}
            setAlertThreshold={setAlertThreshold}
            isOpen={showAlertSettings}
            onClose={() => setShowAlertSettings(false)}
          />
        )}
      </AnimatePresence>
      
      {/* Audio Control Button */}
      <div className="fixed bottom-4 right-4 z-50 flex items-center gap-2">
        <button
          onClick={() => setShowAlertSettings(!showAlertSettings)}
          data-testid="alert-settings-btn"
          className="p-2 rounded-full bg-zinc-800 text-zinc-400 hover:text-white border border-zinc-700 transition-all"
          title="Alert Settings"
        >
          <Settings className="w-4 h-4" />
        </button>
        <button
          onClick={() => setAudioEnabled(!audioEnabled)}
          data-testid="toggle-audio-alerts"
          className={`p-3 rounded-full transition-all ${
            audioEnabled 
              ? 'bg-primary/20 text-primary border border-primary/30' 
              : 'bg-zinc-800 text-zinc-500 border border-zinc-700'
          }`}
          title={audioEnabled ? 'Disable audio alerts' : 'Enable audio alerts'}
        >
          {audioEnabled ? <Volume2 className="w-5 h-5" /> : <VolumeX className="w-5 h-5" />}
        </button>
      </div>
      
      {/* Alert Threshold Indicator */}
      {audioEnabled && (
        <div className="fixed bottom-4 right-28 z-50 glass-panel px-3 py-2 text-xs text-zinc-400 font-mono">
          Alert: ±{alertThreshold}%
        </div>
      )}
      
      {/* Training Mode Indicator - shows when AI training is active */}
      <TrainingModeIndicator />
      
      <main className="ml-[52px] min-h-screen relative">
        {/* Vibrant gradient orbs for visual pop */}
        <div className="fixed inset-0 ml-[52px] pointer-events-none overflow-hidden">
          <div className="absolute -top-1/4 -right-1/4 w-2/3 h-2/3 bg-cyan-500/[0.1] rounded-full blur-[150px]" />
          <div className="absolute top-1/3 -left-1/4 w-1/2 h-1/2 bg-purple-500/[0.08] rounded-full blur-[120px]" />
          <div className="absolute -bottom-1/4 right-1/4 w-2/3 h-2/3 bg-pink-500/[0.06] rounded-full blur-[150px]" />
          <div className="absolute top-1/2 right-0 w-1/3 h-1/3 bg-cyan-400/[0.05] rounded-full blur-[100px]" />
        </div>
        
        {/* Ticker Tape with glass effect */}
        <div className="glass-header sticky top-0 z-10">
          <TickerTape indices={dashboardData.overview?.indices} isConnected={isConnected} lastUpdate={lastUpdate} />
        </div>
        
        {/* Main Content Area - Tabs stay mounted to preserve state */}
        <div className="p-6">
          {/* Command Center - always mounted, hidden when not active */}
          <div style={{ display: activeTab === 'command-center' ? 'block' : 'none' }}>
            <ErrorBoundary name="command-center">
              <CommandCenterPage {...ibProps} isActiveTab={activeTab === 'command-center'} />
            </ErrorBoundary>
          </div>
          
          {/* NIA - always mounted, hidden when not active */}
          <div style={{ display: activeTab === 'nia' ? 'block' : 'none' }}>
            <ErrorBoundary name="NIA">
              <NIA wsConfidenceGate={wsConfidenceGate} wsTrainingStatus={wsTrainingStatus} wsMarketRegime={wsMarketRegime} />
            </ErrorBoundary>
          </div>
          
          {/* Other tabs - render on demand (less frequently used) */}
          {activeTab !== 'command-center' && activeTab !== 'nia' && (
            <ErrorBoundary name={activeTab}>
              {renderPage()}
            </ErrorBoundary>
          )}
        </div>
      </main>
      
      {/* ConnectionStatus removed - redundant with System Status dropdown */}
        </>
      )}
      </div>
    </TickerModalProvider>
    </WebSocketDataProvider>
    </DataCacheProvider>
    </TrainCommandProvider>
    </TrainingModeProvider>
    </FocusModeProvider>
    </ConnectionManagerProvider>
    </SystemStatusProvider>
    </StartupManagerProvider>
    </AppStateProvider>
  );
}

export default App;
